from concurrent import futures
import hashlib
import time
import grpc

import auth_data_pb2
import auth_data_pb2_grpc


class AuthService(auth_data_pb2_grpc.AuthServiceServicer):
    def __init__(self):
        self.users = {
            "alice": "password123",
            "bob": "secret456",
        }
        self.tokens = {}

    def Login(self, request, context):
        username = request.username
        password = request.password

        if username in self.users and self.users[username] == password:
            token = hashlib.sha256(f"{username}:{password}:{time.time()}".encode()).hexdigest()
            self.tokens[token] = username
            return auth_data_pb2.LoginResponse(
                success=True,
                token=token,
                message="Login successful",
            )

        return auth_data_pb2.LoginResponse(
            success=False,
            token="",
            message="Invalid credentials",
        )

    def ValidateToken(self, request, context):
        username = self.tokens.get(request.token, "")
        return auth_data_pb2.ValidateTokenResponse(
            valid=bool(username),
            username=username,
        )


class DataService(auth_data_pb2_grpc.DataServiceServicer):
    def __init__(self, auth_service):
        self.auth_service = auth_service
        self.data_store = {
            "1": "Resource data for item 1",
            "2": "Resource data for item 2",
            "3": "Resource data for item 3",
        }

    def GetData(self, request, context):
        username = self.auth_service.tokens.get(request.token)
        if not username:
            return auth_data_pb2.DataResponse(
                success=False,
                data="",
                message="Unauthorized: invalid token",
            )

        data = self.data_store.get(request.resource_id)
        if data is None:
            return auth_data_pb2.DataResponse(
                success=False,
                data="",
                message="Resource not found",
            )

        return auth_data_pb2.DataResponse(
            success=True,
            data=f"{data} | requested by {username}",
            message="Data retrieval successful",
        )


